const j = $input.first()?.json || {};
const raw = String(j.output || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');

if (!raw.trim()) throw new Error('没有找到 output 文本');

const productName = String(j['产品名称'] || j.product_name || '').trim();
const language = String(j.language || j['视频语言'] || '').trim(); // 仅透传，不翻译

// 轻度清洗：只处理首尾空白，不破坏段落结构
function cleanBlock(s) {
  return String(s || '')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+\n/g, '\n')   // 行尾空格
    .trim();
}

// ---------- 1) 解析 meta（兼容英文一行 meta + 中文风格标签） ----------
let art = '';
let render = '';
let mood = '';

const lines = raw.split('\n');

// 英文 meta：同你原来的逻辑
const metaLine = lines
  .map(l => l.trim())
  .filter(Boolean)
  .find(l => /Art Style/i.test(l) && /Render Quality/i.test(l) && /Mood/i.test(l)) || '';

if (metaLine) {
  const artMatch = metaLine.match(/Art Style\]\*{0,2}\s*([^,]+)\s*,/i);
  const rqMatch  = metaLine.match(/Render Quality\]\*{0,2}\s*([^,]+)\s*,/i);
  const moodMatch= metaLine.match(/Mood\]\*{0,2}\s*([^.\n]+)\.?/i);
  art = cleanBlock(artMatch?.[1]);
  render = cleanBlock(rqMatch?.[1]);
  mood = cleanBlock(moodMatch?.[1]);
} else {
  // 中文风格标签：匹配 “- 画风/类型：xxx” 这种
  const txt = raw;
  const artCn = txt.match(/画风\/类型：\s*([^\n]+)/);
  const rqCn  = txt.match(/画质：\s*([^\n]+)/);
  const moodCn= txt.match(/氛围：\s*([^\n]+)/);
  art = cleanBlock(artCn?.[1]);
  render = cleanBlock(rqCn?.[1]);
  mood = cleanBlock(moodCn?.[1]);
}

// ---------- 2) 解析 shots（先试英文 Shot，再试中文 镜头） ----------
const shots = [];

// 英文 Shot
const shotEnRegex =
  /\*{0,2}Shot\s+(\d+)\s*\(([^)]+)\)\s*:\*{0,2}\s*([\s\S]*?)(?=(?:\n\s*\n)?\*{0,2}Shot\s+\d+\s*\(|$)/gi;

// 中文 镜头：支持 “镜头1（00:00 - 00:01.5）：”
const shotCnRegex =
  /镜头\s*(\d+)\s*[（(]([^）)]+)[）)]\s*[:：]\s*([\s\S]*?)(?=\n\s*镜头\s*\d+\s*[（(]|$)/g;

function normalizeTimeRange(t) {
  const time_range = cleanBlock(t);
  if (!time_range) return '';
  // 如果没有 '-'，补成同点区间
  return time_range.includes('-') ? time_range : `${time_range} - ${time_range}`;
}

function replacePlaceholders(body) {
  let b = body;

  if (productName) {
    b = b.replace(/\b\[HERO_PRODUCT\]\b/g, productName);
  }
  b = b.replace(/\b\[USER\/MODEL\]\b/g, 'a relatable on-camera creator');
  return b;
}

function collectByRegex(regex, type) {
  let m;
  while ((m = regex.exec(raw)) !== null) {
    const no = Number(m[1]);
    const time_range = normalizeTimeRange(m[2]);
    let body = cleanBlock(m[3]);

    body = replacePlaceholders(body);

    // 不改写你原来的内容结构，只包一层 “Shot x”
    shots.push(`**Shot ${no} (${time_range}):**\n${body}`);
  }
}

// 先英文后中文
collectByRegex(shotEnRegex, 'en');
if (shots.length === 0) collectByRegex(shotCnRegex, 'cn');

// ---------- 3) 拼成 Sora prompt（关键：无论解析成不成功，都不丢内容） ----------
const headerParts = [];
if (art) headerParts.push(`[Art Style] ${art}`);
if (render) headerParts.push(`[Render Quality] ${render}`);
if (mood) headerParts.push(`[Mood] ${mood}`);

const header = headerParts.length
  ? `${headerParts.join(', ')}.`
  : `[Art Style] UGC handheld, [Render Quality] mobile phone portrait 9:16, [Mood] authentic and persuasive.`;

const baseRules = cleanBlock(`
${header}
${language ? `Language: ${language}.` : ``}

Cinematic but authentic UGC pacing. Keep camera moves, timing, and beat order exactly as the shot list.
No watermark, no UI icons, no subtitles unless explicitly specified in the shot text.
Vertical 9:16, handheld realism, natural lighting.
`);

// ✅ 如果 shots 解析到了：用结构化 shots
// ✅ 如果 shots 解析不到：fallback 直接塞 raw，保证“不丢字”
const sora_body = shots.length
  ? shots.join('\n\n')
  : cleanBlock(`(Fallback: could not parse shot blocks, using original content)\n\n${raw}`);

const sora_prompt = cleanBlock(`${baseRules}\n\n${sora_body}`);

// 更短版本：同样不丢字（解析失败就塞 raw）
const sora_prompt_compact = cleanBlock(`
${header}
Vertical 9:16 UGC handheld realism. Keep timing and shot order.
${shots.length ? shots.join('\n') : raw}
`);

return [{
  json: {
    ...j,
    sora_prompt,
    sora_prompt_compact,
    shots_count: shots.length
  }
}];

