const j = $input.first()?.json || {};
const raw = String(j.output || '').trim();

if (!raw) throw new Error('没有找到 output 文本');

// 你上游如果有产品名就会自动替换；没有就保留原文
const productName = String(j['产品名称'] || j.product_name || '').trim();

// 可选：你希望输出什么语言（不传就按原文）
const language = String(j.language || j['视频语言'] || '').trim(); // 仅透传展示，不做翻译

function clean(s) {
  return String(s || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n').trim();
}

// -------- 1) 解析 meta 行 --------
const lines = raw.split('\n').map(l => l.trim()).filter(Boolean);
const metaLine = lines.find(l => /Art Style/i.test(l) && /Render Quality/i.test(l) && /Mood/i.test(l)) || '';

let art = '';
let render = '';
let mood = '';

if (metaLine) {
  const artMatch = metaLine.match(/Art Style\]\*{0,2}\s*([^,]+)\s*,/i);
  const rqMatch  = metaLine.match(/Render Quality\]\*{0,2}\s*([^,]+)\s*,/i);
  const moodMatch= metaLine.match(/Mood\]\*{0,2}\s*([^.\n]+)\.?/i);

  art = clean(artMatch?.[1]);
  render = clean(rqMatch?.[1]);
  mood = clean(moodMatch?.[1]);
}

// -------- 2) 解析 shots --------
const shotRegex = /\*{0,2}Shot\s+(\d+)\s*\(([^)]+)\)\s*:\*{0,2}\s*([\s\S]*?)(?=(?:\n\s*\n)?\*{0,2}Shot\s+\d+\s*\(|$)/gi;

const shots = [];
let m;
while ((m = shotRegex.exec(raw)) !== null) {
  const no = Number(m[1]);
  let time_range = clean(m[2]);
  let body = clean(m[3]);

  // 统一 time_range：如果只有单点 "00:15"，就补成 "00:15 - 00:15"
  if (!time_range.includes('-')) {
    time_range = `${time_range} - ${time_range}`;
  }

  // 可选：替换占位符
  if (productName) {
    body = body.replace(/\b\[HERO_PRODUCT\]\b/g, productName);
    // 有些文本里直接写了产品名，不动；仅处理占位符
  }
  body = body.replace(/\b\[USER\/MODEL\]\b/g, 'a relatable on-camera creator');

  // 规范 Lighting / Auxiliary 位置（保持原信息，但更适合 Sora）
  // 让内容更像“镜头指令”
  shots.push(`**Shot ${no} (${time_range}):** ${body}`);
}

// -------- 3) 拼成 Sora 整段提示词 --------
// 这里加一些通用约束（不会删你内容，只是包一层 Sora 生成指令）
const headerParts = [];
if (art) headerParts.push(`[Art Style] ${art}`);
if (render) headerParts.push(`[Render Quality] ${render}`);
if (mood) headerParts.push(`[Mood] ${mood}`);

const header = headerParts.length
  ? `${headerParts.join(', ')}.`
  : `[Art Style] UGC selfie video, [Render Quality] mobile phone portrait 9:16, [Mood] authentic and persuasive.`;

const sora_prompt = clean(`
${header}
${language ? `Language: ${language}.` : ``}

Cinematic but authentic UGC pacing. Keep camera moves, timing, and beat order exactly as the shot list.
No watermark, no UI icons, no subtitles unless explicitly specified in the shot text.
Vertical 9:16, handheld realism, natural lighting.

${shots.join('\n\n')}
`);

// 更短更省 token 的版本（可选）
const sora_prompt_compact = clean(`
${header}
Vertical 9:16 UGC selfie realism. Keep timing and shot order.
${shots.join('\n')}
`);

return [{
  json: {
    ...j,
    sora_prompt,
    sora_prompt_compact,
    shots_count: shots.length
  }
}];

